import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';
import '../review.dart';

class ReviewPopupWidget extends StatelessWidget {
  final String targetName;
  final String? destinationId;

  const ReviewPopupWidget({
