          padding: const EdgeInsets.fromLTRB(24, 32, 24, 28),
          decoration: ShapeDecoration(
            color: Colors.white,
            shape: RoundedRectangleBorder(
              borderRadius: BorderRadius.circular(20),
            ),
            shadows: const [
              BoxShadow(
                color: Color(0x4C000000),
                blurRadius: 20,
                offset: Offset(0, 4),
              ),
            ],
          ),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              // ── Illustration ──────────────────────────────────
              SvgPicture.string(
                '''<svg width="148" height="147" viewBox="0 0 148 147" fill="none" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
<rect x="-0.000244141" width="147.293" height="146.4" fill="url(#pattern0_1182_2236)"/>
<defs>
<pattern id="pattern0_1182_2236" patternContentUnits="objectBoundingBox" width="1" height="1">
<use xlink:href="#image0_1182_2236" transform="scale(0.000257732 0.000283046)"/>
</pattern>
<image id="image0_1182_2236" width="3880" height="3533" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
</defs>
</svg>
''',
                width: 148,
                height: 147,
              ),

              const SizedBox(height: 16),

              // ── Drag handle ───────────────────────────────────
              Container(
                width: 100,
                height: 2,
                decoration: BoxDecoration(
                  color: const Color(0xFF999999),
                  borderRadius: BorderRadius.circular(2),
                ),
              ),

              const SizedBox(height: 20),

              // ── Title ─────────────────────────────────────────
              const Text(
                "We'd love to hear from you",
                textAlign: TextAlign.center,
                style: TextStyle(
                  fontFamily: 'Poppins',
                  fontWeight: FontWeight.w700,
                  fontSize: 16,
                  color: Colors.black,
                ),
              ),

              const SizedBox(height: 6),

              // ── Subtitle ──────────────────────────────────────
              const Text(
                'Spare some minute and give your thought',
                textAlign: TextAlign.center,
                style: TextStyle(
                  fontFamily: 'Poppins',
                  fontWeight: FontWeight.w400,
                  fontSize: 13,
                  color: Colors.black54,
                ),
              ),

              const SizedBox(height: 16),

              // ── CTA link ──────────────────────────────────────
              GestureDetector(
                onTap: () {
